option.value:
---
import Layout from '../layouts/Layout.astro';
import { Image } from 'astro:assets';
import sam from '../assets/sam.png';
import shaurya from '../assets/shaurya.png';
import aman from '../assets/aman.png';
import dheeksha from '../assets/dheeksha.png';
import rohan from '../assets/rohan.jpeg';
import coopy from '../assets/coopy.png';
import snoopy from '../assets/snoopy.png';
import robbie from '../assets/robbie.png';
import lucky from '../assets/lucky.jpg';
---
<Layout title="Our Pawmise" description="OurPawmise helps East Bay pet families afford critical veterinary care through direct grants and education.">
  <main>
    <section class="hero">
      <div class="overlay"></div>
      <div class="wrap hero-content">
        <p class="eyebrow">501(c)(3) nonprofit | all volunteer team</p>
        <h1>Because no pet should lose care due to cost.</h1>
        <p>
          OurPawmise supports East Bay families facing major, non-routine veterinary treatment costs,
          and helps prevent future crises through practical education.
        </p>
        <div class="hero-actions">
          <a href="/support" class="btn btn-primary">Donate</a>
          <a href="/operations-plan" class="btn btn-secondary">Read Operations Plan</a>
        </div>
      </div>
    </section>

    <section id="mission" class="section">
      <div class="wrap narrow">
        <h2>Mission and Vision</h2>
        <p>
          Our mission is to save and improve pet lives by providing financial support for vital
          veterinary care to pet owners in need, and empower families to manage their pets'
          healthcare costs proactively.
        </p>
        <p>
          We envision a future where decisions about a pet's medical care are never made on the
          basis of cost.
        </p>
      </div>
    </section>

    <section id="programs" class="section section-alt">
      <div class="wrap">
        <h2>What We Offer</h2>
        <div class="grid-3">
          <article class="card">
            <h3>Financial Assistance</h3>
            <p>One-time grants for serious, treatable, non-emergency conditions, paid directly to veterinarians.</p>
            <a href="/financial-assistance">Details</a>
          </article>
          <article class="card">
            <h3>Education and Outreach</h3>
            <p>Preventive care, insurance literacy, cost planning, and practical resources for pet families.</p>
            <a href="/education-outreach">Details</a>
          </article>
          <article class="card">
            <h3>Application Process</h3>
            <p>Clear eligibility criteria, case review steps, and direct payment model with transparent follow-up.</p>
            <a href="/application-process">Details</a>
          </article>
        </div>
      </div>
    </section>

    <section id="difference" class="section">
      <div class="wrap">
        <h2>What Sets Us Apart</h2>
        <div class="grid-3">
          <article class="card"><h3>Run by Pet Owners</h3><p>We understand the stress because we have lived it.</p></article>
          <article class="card"><h3>East Bay Focus</h3><p>Local, personalized support tailored to community realities.</p></article>
          <article class="card"><h3>Inclusive of All Pets</h3><p>Dogs, cats, rabbits, birds, and other companion animals.</p></article>
        </div>
      </div>
    </section>

    <section id="team" class="section section-alt">
      <div class="wrap">
        <h2>Founding Team</h2>
        <p class="muted">All members are unpaid volunteers.</p>
        <div class="team-grid">
          <div class="member"><div class="member-photo-frame"><Image src={sam} alt="Samarth Dhingra" class="member-photo" width={220} height={220} loading="lazy" /></div><h3>Samarth Dhingra</h3><p>Founder and Strategy Lead</p></div>
          <div class="member"><div class="member-photo-frame"><Image src={shaurya} alt="Shaurya Gakhar" class="member-photo" width={220} height={220} loading="lazy" /></div><h3>Shaurya Gakhar</h3><p>Education Lead</p></div>
          <div class="member"><div class="member-photo-frame"><Image src={aman} alt="Aman Deshmukh" class="member-photo" width={220} height={220} loading="lazy" /></div><h3>Aman Deshmukh</h3><p>Outreach Lead</p></div>
          <div class="member"><div class="member-photo-frame"><Image src={dheeksha} alt="Dheeksha Kaku" class="member-photo" width={220} height={220} loading="lazy" /></div><h3>Dheeksha Kaku</h3><p>Outreach Executive</p></div>
          <div class="member"><div class="member-photo-frame"><Image src={rohan} alt="Rohan Patel" class="member-photo" width={220} height={220} loading="lazy" /></div><h3>Rohan Patel</h3><p>Outreach Executive</p></div>
        </div>
      </div>
    </section>

    <section id="pets" class="section">
      <div class="wrap">
        <h2>Meet Our Pets</h2>
        <div class="pets-grid">
          <figure><div class="pet-media"><Image src={coopy} alt="Cooper" class="pet-photo" width={840} height={630} loading="lazy" /></div><figcaption><strong>Cooper</strong><span>Golden locks and calm energy.</span></figcaption></figure>
          <figure><div class="pet-media"><Image src={snoopy} alt="Snoopy" class="pet-photo" width={840} height={630} loading="lazy" /></div><figcaption><strong>Snoopy</strong><span>Looks aloof, actually very fun.</span></figcaption></figure>
          <figure class="pet-robbie-card"><div class="pet-media"><Image src={robbie} alt="" aria-hidden="true" class="pet-photo pet-robbie-bg" width={840} height={630} fit="cover" loading="lazy" /><Image src={robbie} alt="Robbie" class="pet-photo pet-robbie" width={840} height={630} fit="contain" loading="lazy" /></div><figcaption><strong>Robbie</strong><span>A big boy with a big heart.</span></figcaption></figure>
          <figure><div class="pet-media"><Image src={lucky} alt="Lucky" class="pet-photo" width={840} height={630} loading="lazy" /></div><figcaption><strong>Lucky</strong><span>Always ready to play.</span></figcaption></figure>
        </div>
      </div>
    </section>

    <section id="contact" class="section section-alt">
      <div class="wrap narrow">
        <h2>Get in Touch</h2>
        <p>Email: <a href="mailto:contact@ourpawmise.org">contact@ourpawmise.org</a></p>
        <p>Instagram: <a href="https://instagram.com/ourpawmise_org" target="_blank" rel="noopener">@ourpawmise_org</a></p>
        <p>East Bay, CA</p>
        <a href="/support" class="btn btn-primary" style="margin-top:1rem;">Make a Donation</a>
      </div>
    </section>
  </main>
</Layout>

<style>
  .hero {
    position: relative;
    min-height: 100svh;
    display: flex;
    align-items: center;
    background: url('https://images.unsplash.com/photo-1450778869180-41d0601e046e?auto=format&fit=crop&w=2000&q=80') center/cover no-repeat;
    color: #fff;
  }
  .overlay { position: absolute; inset: 0; background: rgba(20, 14, 10, 0.56); }
  .hero-content { position: relative; z-index: 1; padding-top: 5rem; max-width: 760px; }
  .eyebrow { font-size: 0.8rem; text-transform: uppercase; letter-spacing: 0.08em; opacity: 0.8; margin-bottom: 1rem; }
  h1 { font-size: clamp(2.2rem, 5vw, 3.6rem); line-height: 1.12; margin-bottom: 1rem; font-weight: 600; }
  .hero p { max-width: 620px; color: rgba(255, 255, 255, 0.9); }
  .hero-actions { margin-top: 1.5rem; display: flex; gap: 0.75rem; flex-wrap: wrap; }

  .section { padding: 4rem 0; }
  .section-alt { background: var(--surface); }
  .narrow { max-width: 760px; }
  .section h2 { font-size: 1.75rem; margin-bottom: 1rem; font-weight: 600; letter-spacing: -0.02em; }
  .section h2::after { content: ''; display: block; width: 2.6rem; height: 2px; margin-top: 0.5rem; background: var(--accent); }
  .section p { color: var(--muted); margin-bottom: 0.85rem; }
  .muted { color: var(--muted); margin-bottom: 1.2rem; }

  .btn {
    display: inline-block;
    border-radius: 6px;
    border: 1px solid transparent;
    padding: 0.7rem 1.4rem;
    font-size: 0.95rem;
    text-decoration: none;
    font-weight: 500;
  }
  .btn-primary { background: var(--accent); color: #fff; }
  .btn-primary:hover { background: var(--accent-hover); }
  .btn-secondary { border-color: rgba(255, 255, 255, 0.45); color: #fff; }
  .btn-secondary:hover { background: rgba(255, 255, 255, 0.1); }

  .grid-3 {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
    gap: 1.25rem;
    margin-top: 1.25rem;
  }
  .card {
    background: var(--bg);
    border: 1px solid var(--border);
    border-radius: 10px;
    padding: 1.5rem;
  }
  .card h3 { font-size: 1.05rem; margin-bottom: 0.5rem; }
  .card p { font-size: 0.95rem; margin-bottom: 0.75rem; }
  .card a { color: var(--accent); font-size: 0.9rem; text-decoration: none; }
  .card a:hover { text-decoration: underline; }

  #contact a:not(.btn) { color: var(--accent); text-decoration: none; }
  #contact a:not(.btn):hover { text-decoration: underline; }

  .team-grid {
    display: flex;
    flex-wrap: wrap;
    justify-content: center;
    gap: 1.5rem;
  }
  .member {
    flex: 0 1 180px;
    text-align: center;
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 12px;
    padding: 1.25rem 1rem;
    transition: transform 0.2s ease, border-color 0.2s ease;
  }
  .member:hover {
    transform: translateY(-2px);
    border-color: #d8c8bf;
  }
  .member-photo-frame {
    width: 130px;
    height: 130px;
    margin: 0 auto 0.85rem;
    border-radius: 50%;
    overflow: hidden;
    border: 3px solid #fff;
    box-shadow: 0 0 0 1px var(--border), 0 8px 18px rgba(28, 25, 23, 0.08);
  }
  .member img.member-photo {
    width: 100%;
    height: 100%;
    object-fit: cover;
    object-position: center;
  }
  .member h3 { font-size: 0.95rem; margin-bottom: 0.25rem; }
  .member p { font-size: 0.85rem; }

  .pets-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));
    gap: 1.25rem;
  }
  .pets-grid figure {
    border: 1px solid var(--border);
    border-radius: 10px;
    overflow: hidden;
    background: var(--surface);
    transition: transform 0.2s ease, border-color 0.2s ease;
  }
  .pets-grid figure:hover {
    transform: translateY(-2px);
    border-color: #d8c8bf;
  }
  .pet-media {
    position: relative;
    overflow: hidden;
    aspect-ratio: 4 / 3;
    background: #f7f5f2;
    isolation: isolate;
  }
  .pets-grid img.pet-photo {
    width: 100%;
    height: 100%;
    object-fit: cover;
    transition: transform 0.35s ease;
  }
  .pets-grid img.pet-robbie {
    object-fit: contain;
    object-position: center;
    background: transparent;
    position: relative;
    z-index: 1;
    transform: none;
  }
  .pets-grid img.pet-robbie-bg {
    position: absolute;
    inset: 0;
    width: 100%;
    height: 100%;
    object-fit: cover;
    filter: blur(18px);
    transform: scale(1.22);
    opacity: 0.72;
    z-index: 0;
    pointer-events: none;
  }
  .pets-grid figure:hover img.pet-photo { transform: scale(1.03); }
  .pets-grid figure:hover img.pet-robbie { transform: none; }
  .pets-grid figure:hover img.pet-robbie-bg { transform: scale(1.22); }
  .pet-robbie-card .pet-media {
    background: #ece7e0;
  }
  .pet-robbie-card .pet-media .pet-robbie { position: relative; z-index: 1; }
  .pets-grid figcaption {
    padding: 1rem;
    border-top: 1px solid var(--border);
    background: linear-gradient(to bottom, #fff, #fcfbfa);
  }
  .pets-grid strong { display: block; font-size: 0.95rem; margin-bottom: 0.25rem; }
  .pets-grid span { color: var(--muted); font-size: 0.875rem; }
</style>

