    overflow: hidden;
    background: var(--surface);
    transition: transform 0.2s ease, border-color 0.2s ease;
  }
  .pets-grid figure:hover {
    transform: translateY(-2px);
    border-color: #d8c8bf;
  }
  .pet-media {
    position: relative;
    overflow: hidden;
    aspect-ratio: 4 / 3;
    background: #f7f5f2;
    isolation: isolate;
  }
  .pets-grid img.pet-photo {
    width: 100%;
    height: 100%;
    object-fit: cover;
    transition: transform 0.35s ease;
  }
  .pets-grid img.pet-robbie {
    object-fit: contain;
    object-position: center;
    background: transparent;
    position: relative;
    z-index: 1;
    transform: none;
  }
  .pets-grid img.pet-robbie-bg {
    position: absolute;
    inset: 0;
    width: 100%;
    height: 100%;
    object-fit: cover;
    filter: blur(18px);
    transform: scale(1.22);
    opacity: 0.72;
    z-index: 0;
    pointer-events: none;
  }
  .pets-grid figure:hover img.pet-photo { transform: scale(1.03); }
  .pets-grid figure:hover img.pet-robbie { transform: none; }
  .pets-grid figure:hover img.pet-robbie-bg { transform: scale(1.22); }
  .pet-robbie-card .pet-media {
    background: #ece7e0;
  }
  .pet-robbie-card .pet-media .pet-robbie { position: relative; z-index: 1; }
  .pets-grid figcaption {
    padding: 1rem;
    border-top: 1px solid var(--border);
    background: linear-gradient(to bottom, #fff, #fcfbfa);
  }
  .pets-grid strong { display: block; font-size: 0.95rem; margin-bottom: 0.25rem; }
  .pets-grid span { color: var(--muted); font-size: 0.875rem; }
</style>

---
import Layout from '../layouts/Layout.astro';
---
<Layout title="Thank You – Our Pawmise">
  <main class="page">
    <div class="wrap page-inner">
      <div class="thank-card">
        <div class="icon">♥</div>
        <h1>Thank you!</h1>
        <p>Your contribution goes directly toward providing critical veterinary care to animals who need it most. We are so grateful for your support — every dollar counts.</p>
        <a href="/" class="btn">Back to Home</a>
      </div>
    </div>
  </main>
</Layout>

<style>
  .page {
    padding-top: 60px;
    min-height: 100svh;
    display: flex;
    align-items: center;
    background: var(--bg);
  }
  .page-inner {
    padding-top: 3rem;
    padding-bottom: 5rem;
    display: flex;
    justify-content: center;
  }
  .thank-card {
    max-width: 480px;
    width: 100%;
    text-align: center;
    border: 1px solid var(--border);
    border-radius: 16px;
    padding: 3rem 2.5rem;
    background: var(--surface);
  }
  .icon {
    font-size: 2.5rem;
    color: var(--accent);
    margin-bottom: 1rem;
  }
  h1 {
    font-size: 2rem;
    font-weight: 600;
    letter-spacing: -0.03em;
    margin-bottom: 1rem;
  }
  p {
    font-size: 0.925rem;
    color: var(--muted);
    line-height: 1.65;
    margin-bottom: 2rem;
  }
  .btn {
    display: inline-block;
    padding: 0.65rem 1.75rem;
    border-radius: 6px;
    font-size: 0.9rem;
    font-weight: 500;
    text-decoration: none;
    background: var(--accent);
    color: #fff;
    transition: background 0.2s;
  }
  .btn:hover { background: var(--accent-hover); }
</style>

